  ('real-estate-moex-02695', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '甲、乙、丙三人共有土地一筆，持分各三分之一。請問下列敘述何者正確？', '["甲出售其應有部分三分之一時，不須乙、丙之同意", "只須甲、乙之同意，即可就共有土地之全部設定抵押權", "甲將其應有部分出售予丙時，乙得主張優先購買權", "須經甲、乙、丙三人全體同意，才能申請地政機關之調處分割"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "bd36ff652b84", "answer_pdf_sha1": "020b5ff7d4ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02696', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列何者非屬都市計畫法規定都市計畫迅行變更之原因﹖', '["因災害或其他重大事變遭受損壞時", "為避免重大災害之發生時", "土地權利關係人為促進其土地利用時", "為適應國防或經濟發展之需要時"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "bd36ff652b84", "answer_pdf_sha1": "020b5ff7d4ca", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
